import Link from "next/link"
import { DocsShell } from "@/components/docs/DocsShell"
import { getAllDocs } from "@/lib/docs/docs.source"

export default function DocsIndexPage() {
  const docs = getAllDocs().slice(0, 8)

  return (
    <DocsShell
      title="Documentation AKFC"
      description="Documentation technique et pédagogique du projet."
    >
      <p>
        Cette section transforme le dossier <code>content/docs</code> en véritable site
        de documentation.
      </p>

      <h2>Documents disponibles</h2>

      <ul>
        {docs.map((doc) => (
          <li key={doc.href}>
            <Link href={doc.href}>{doc.title}</Link>
          </li>
        ))}
      </ul>
    </DocsShell>
  )
}
